#include <iostream>
using namespace std;

long fibonacciIterative(int n)
{
    if (n <= 1) return n;

    long a = 0, b = 1;
    for (int i = 2; i <= n; i++)
    {
        long temp = a + b;
        a = b;
        b = temp;
    }
    return b;
}

long fibonacciRecursive(int n)
{
    if (n <= 1) return n;
    return fibonacciRecursive(n - 1) + fibonacciRecursive(n - 2);
}

int main()
{
    cout << "Iteratif Fibonacci (0-10):" << endl;
    for (int i = 0; i <= 10; i++)
    {
        cout << fibonacciIterative(i) << " ";
    }
    cout << endl;

    cout << "\nRecursive Fibonacci (0-10):" << endl;
    for (int i = 0; i <= 10; i++)
    {
        cout << fibonacciRecursive(i) << " ";
    }
    cout << endl;

    cout << "\n20. Fibonacci sayisi: " << fibonacciIterative(20) << endl;

    return 0;
}
